const PAT_HTML = '<div class="ph"><div class="pt" style="color:var(--pat)">Pattern Recognition</div><div class="ps">Classic diagnostic combinations at the bedside</div></div>\n\n  <div class="ps2"><h2>Anaemia classification by MCV</h2>\n  <table class="ptbl">\n    <thead><tr><th>Type</th><th>MCV</th><th>RDW</th><th>Key finding</th><th>Diagnosis</th><th>Next step</th></tr></thead>\n    <tbody>\n      <tr><td><span class="badge b-mi">Microcytic</span></td><td class="td2">&lt;80</td><td class="tu">↑</td><td>Ferritin ↓, TIBC ↑</td><td>Iron deficiency ★</td><td>Find source of loss</td></tr>\n      <tr><td><span class="badge b-mi">Microcytic</span></td><td class="td2">&lt;80</td><td class="tn">Normal</td><td>Hb electrophoresis abnormal</td><td>Thalassaemia trait</td><td>HPLC, family Hx</td></tr>\n      <tr><td><span class="badge b-mi">Microcytic</span></td><td class="td2">&lt;80</td><td class="tn">N/↑</td><td>Ferritin ↑, TIBC ↓, chronic illness</td><td>Anaemia of chronic disease</td><td>Treat underlying</td></tr>\n      <tr><td><span class="badge b-n">Normocytic</span></td><td class="tn">80–100</td><td class="tu">↑</td><td>Retics ↑, LDH ↑, bili ↑, haptoglobin ↓</td><td>Haemolysis</td><td>DAT, blood film</td></tr>\n      <tr><td><span class="badge b-n">Normocytic</span></td><td class="tn">80–100</td><td class="tn">Normal</td><td>Retics ↓, pancytopenia</td><td>Aplastic anaemia</td><td>Bone marrow biopsy</td></tr>\n      <tr><td><span class="badge b-ma">Macrocytic</span></td><td class="tu">&gt;100</td><td class="tu">↑</td><td>Hypersegmented neutrophils, B12/folate ↓</td><td>Megaloblastic anaemia</td><td>B12, folate, MMA</td></tr>\n      <tr><td><span class="badge b-ma">Macrocytic</span></td><td class="tu">&gt;100</td><td class="tn">Normal/↑</td><td>GGT ↑, alcohol history</td><td>Alcohol/liver disease</td><td>LFTs, GGT, AUDIT</td></tr>\n    </tbody>\n  </table></div>\n\n  <div class="ps2"><h2>Jaundice pattern — pre / hepatic / post-hepatic</h2>\n  <table class="ptbl">\n    <thead><tr><th>Type</th><th>Bilirubin</th><th>ALP</th><th>ALT/AST</th><th>Urine bili</th><th>Urobilinogen</th><th>Stool</th><th>Example</th></tr></thead>\n    <tbody>\n      <tr><td><span class="badge b-pre">Pre-hepatic</span></td><td>Unconj ↑</td><td class="tn">N</td><td class="tn">N</td><td class="tn">Absent</td><td class="tu">↑↑</td><td>Normal</td><td>Haemolysis, Gilbert\'s</td></tr>\n      <tr><td><span class="badge b-int">Hepatic</span></td><td>Both ↑</td><td class="tu">↑</td><td class="tu">↑↑↑</td><td class="tu">Present</td><td>Low/N</td><td>Normal/pale</td><td>Hepatitis, cirrhosis</td></tr>\n      <tr><td><span class="badge b-pos">Post-hepatic</span></td><td>Conj ↑↑</td><td class="tu">↑↑↑</td><td class="tu">↑</td><td class="tu">Present (dark)</td><td class="td2">Absent</td><td>Pale/clay</td><td>Gallstones, Ca pancreas</td></tr>\n    </tbody>\n  </table>\n  <div class="infobox">Dark urine + pale stool + itch = obstructive. Charcot\'s triad = fever + RUQ pain + jaundice (cholangitis). Painless jaundice + weight loss = Ca head of pancreas until proven otherwise (Courvoisier\'s law).</div></div>\n\n  <div class="ps2"><h2>AKI classification</h2>\n  <table class="ptbl">\n    <thead><tr><th>Type</th><th>Urea:Creat ratio</th><th>Urine Na</th><th>Urine Osm</th><th>FENa</th><th>Causes</th></tr></thead>\n    <tbody>\n      <tr><td><span class="badge b-pre">Pre-renal</span></td><td class="tu">&gt;100:1</td><td class="td2">&lt;20</td><td class="tu">&gt;500</td><td>&lt;1%</td><td>Dehydration, CCF, sepsis, haemorrhage</td></tr>\n      <tr><td><span class="badge b-int">Intrinsic</span></td><td class="td2">&lt;100:1</td><td class="tu">&gt;40</td><td class="td2">&lt;350</td><td>&gt;2%</td><td>ATN ★, GN, interstitial nephritis</td></tr>\n      <tr><td><span class="badge b-pos">Post-renal</span></td><td>Variable</td><td>Variable</td><td>Variable</td><td>Variable</td><td>BPH ★, calculi, tumour</td></tr>\n    </tbody>\n  </table></div>\n\n  <div class="ps2"><h2>Diabetes diagnosis criteria (WHO)</h2>\n  <table class="ptbl">\n    <thead><tr><th>Test</th><th>Normal</th><th>Pre-diabetes / IGT</th><th>Diabetes</th></tr></thead>\n    <tbody>\n      <tr><td>Fasting glucose</td><td class="tn">&lt;6.0 mmol/L</td><td>6.1–6.9 mmol/L (IFG)</td><td class="tu">≥7.0 mmol/L</td></tr>\n      <tr><td>2-hr OGTT (75g)</td><td class="tn">&lt;7.8 mmol/L</td><td>7.8–11.0 mmol/L (IGT)</td><td class="tu">≥11.1 mmol/L</td></tr>\n      <tr><td>Random glucose</td><td>—</td><td>—</td><td class="tu">≥11.1 mmol/L + symptoms</td></tr>\n      <tr><td>HbA1c</td><td class="tn">&lt;42 mmol/mol (&lt;6.0%)</td><td>42–47 mmol/mol (6.0–6.4%)</td><td class="tu">≥48 mmol/mol (≥6.5%)</td></tr>\n    </tbody>\n  </table>\n  <div class="infobox">One test sufficient if symptomatic. Two separate tests required if asymptomatic. HbA1c unreliable in haemoglobinopathy, haemolysis, pregnancy, CKD — use plasma glucose instead.</div></div>\n\n  <div class="ps2"><h2>Hypercalcaemia — primary vs malignancy</h2>\n  <table class="ptbl">\n    <thead><tr><th>Feature</th><th>Primary hyperparathyroidism</th><th>Malignancy-related</th></tr></thead>\n    <tbody>\n      <tr><td>PTH</td><td class="tu">↑ (inappropriately normal/high)</td><td class="td2">↓ (suppressed)</td></tr>\n      <tr><td>PTHrP</td><td class="tn">Normal</td><td class="tu">↑ (humoral hypercalcaemia)</td></tr>\n      <tr><td>Phosphate</td><td class="td2">↓</td><td>Variable</td></tr>\n      <tr><td>ALP</td><td>Normal / mild ↑</td><td class="tu">↑↑ (bone mets)</td></tr>\n      <tr><td>Chloride</td><td class="tu">↑ (hyperchloraemic)</td><td>Normal</td></tr>\n      <tr><td>Vitamin D</td><td>Normal</td><td>Normal (unless sarcoid)</td></tr>\n      <tr><td>Onset</td><td>Chronic, often asymptomatic</td><td>Acute, symptomatic (Ca often very high)</td></tr>\n    </tbody>\n  </table></div>\n\n  <div class="ps2"><h2>CKD staging (KDIGO)</h2>\n  <table class="ptbl">\n    <thead><tr><th>Stage</th><th>eGFR</th><th>Description</th><th>Key actions</th></tr></thead>\n    <tbody>\n      <tr><td>G1</td><td>&gt;90 + markers</td><td>Normal with damage markers</td><td>Treat cause, BP control &lt;130/80</td></tr>\n      <tr><td>G2</td><td>60–89</td><td>Mildly decreased</td><td>Monitoring, risk factor modification</td></tr>\n      <tr><td>G3a</td><td>45–59</td><td>Mild–moderate</td><td>Avoid NSAIDs, caution contrast, check for anaemia</td></tr>\n      <tr><td>G3b</td><td>30–44</td><td>Moderate–severe</td><td>Stop metformin, adjust doses, consider EPO</td></tr>\n      <tr><td>G4</td><td>15–29</td><td>Severely decreased</td><td>Nephrology referral, plan RRT, AV fistula</td></tr>\n      <tr><td>G5</td><td>&lt;15</td><td>Kidney failure</td><td>Dialysis or transplant</td></tr>\n    </tbody>\n  </table></div>\n</div>\n\n<!-- ═══ MNEMONICS ═══ -->';

