hep:[
  {t:"Hepatoprotective Herbs — Liver Support",badge:"Organ",c:`
    <table class="tbl"><thead><tr><th>Herb</th><th>Active Compounds</th><th>Mechanism</th><th>Best Evidence</th><th>Dose</th></tr></thead><tbody>
      <tr><td>Milk Thistle</td><td>Silymarin (silibinin)</td><td>Antioxidant (↑ GSH), membrane stabiliser, anti-fibrotic, ↑ protein synthesis</td><td>Cirrhosis, hepatitis (viral, alcoholic), Amanita poisoning ★</td><td>420mg/day silymarin</td></tr>
      <tr><td>Dandelion root</td><td>Taraxacin, inulin, bitter sesquiterpenes</td><td>↑ Bile flow, mild diuretic, prebiotic, anti-inflammatory</td><td>Liver congestion, constipation, UTI</td><td>4–10g root/day or tincture</td></tr>
      <tr><td>Globe artichoke</td><td>Cynarin, luteolin</td><td>↑ Bile production/flow, hepatoprotective, lipid-lowering</td><td>Dyslipidaemia ★, NAFLD, dyspepsia</td><td>320–640mg extract/day</td></tr>
      <tr><td>Turmeric / Curcumin</td><td>Curcuminoids</td><td>NF-κB ↓, COX-2 ↓, Nrf2 ↑, anti-fibrotic</td><td>NAFLD ★, IBD, arthritis, cancer adjunct</td><td>500–2000mg/day + piperine or liposomal</td></tr>
      <tr><td>Andrographis</td><td>Andrographolide</td><td>Anti-viral, NF-κB ↓, immune modulation</td><td>Viral hepatitis, URTI, IBD</td><td>200–400mg andrographolide/day</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Curcumin bioavailability — critical</div><div class="pt">Curcumin has only 1% oral bioavailability as standard powder. Solutions: (1) Piperine (black pepper extract, bioperine) 20mg increases absorption 2000%, (2) Liposomal/phospholipid complex (Meriva, BCM-95) 7–29× increase, (3) Nanoparticle formulations. Always specify the formulation when recommending. BCM-95 or Meriva at 500mg/day equals 8–10g standard curcumin powder.</div></div>`}
],
nrv:[
  {t:"Nervines & Neurological Herbs",badge:"Category",c:`
    <table class="tbl"><thead><tr><th>Herb</th><th>Category</th><th>Mechanism</th><th>Best Use</th><th>Dose</th></tr></thead><tbody>
      <tr><td>Ashwagandha</td><td>Adaptogen-nervine</td><td>↓ Cortisol, GABA-A modulation, BDNF ↑</td><td>Anxiety + fatigue, adrenal fatigue</td><td>KSM-66 300mg twice daily</td></tr>
      <tr><td>Valerian</td><td>Sedative nervine</td><td>GABA transaminase inhibition, GABA-A agonism</td><td>Insomnia ★, anxiety, muscle tension</td><td>400–900mg 30min before bed</td></tr>
      <tr><td>Passionflower</td><td>Anxiolytic nervine</td><td>GABA-A potentiation (similar to benzos, no dependence)</td><td>Anxiety ★, insomnia, withdrawal support</td><td>250–500mg or tincture</td></tr>
      <tr><td>Lemon balm</td><td>Relaxing nervine</td><td>MAO inhibition (mild), GABA-T inhibition, antiviral</td><td>Anxiety, insomnia, cold sores, ADHD (children)</td><td>300–600mg (or tea)</td></tr>
      <tr><td>Bacopa monnieri</td><td>Nootropic</td><td>↑ Acetylcholine, antioxidant, ↑ BDNF, adaptogenic</td><td>Memory ★, ADHD adjunct, cognitive ageing</td><td>300mg/day standardised (must take 8–12 weeks)</td></tr>
      <tr><td>Lion's Mane</td><td>Nootropic mushroom</td><td>NGF (nerve growth factor) stimulation, remyelination</td><td>Cognitive decline ★, neuropathy, depression</td><td>500–3000mg/day extract</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Lion's Mane & NGF</div><div class="pt">Hericium erinaceus (Lion's Mane) is the only known food that stimulates NGF (nerve growth factor) synthesis in the brain. NGF promotes neuroplasticity, remyelination, and neurogenesis. RCT evidence for mild cognitive impairment (Mori et al., 2009 — 50% cognitive improvement vs placebo over 16 weeks). Requires 8 weeks minimum. Use hot-water extract (fruiting body) not mycelium for NGF-stimulating hericenones and erinacines.</div></div>`}
]
