const D_NATASSESS = {
nat:[
  {t:"Naturopathic History Taking — Complete Framework",badge:"Foundation",c:`
    <div class="alert a-grn"><div class="a-label">Naturopathic History = SOAP + VITALS + DIET + MIND + SPIRIT</div>A comprehensive naturopathic history takes 45–60 min for new patients. Every symptom has a physical, mental, emotional, and spiritual component. Never rush this — it IS the diagnosis.</div>
    <div class="steps">
      <div class="step"><div class="sn" style="background:#064E3B">1</div><div class="st"><span class="sh">Chief Complaint & History</span> Duration, onset, character, radiation, aggravating/relieving factors, timing. WHAT makes it better? WHAT makes it worse? WHAT was happening in life when it started? (Emotional triggers are often the true cause.)</div></div>
      <div class="step"><div class="sn" style="background:#064E3B">2</div><div class="st"><span class="sh">Dietary History (24-hr recall)</span> What did you eat yesterday — breakfast, lunch, dinner, snacks, drinks? Water intake? Cooking method? Food intolerances? Emotional eating? Eating times? Eating speed? Note: meal timing affects circadian biology significantly.</div></div>
      <div class="step"><div class="sn" style="background:#064E3B">3</div><div class="st"><span class="sh">Sleep History</span> Hours/night, sleep onset time, wake time, dream recall, night sweats, snoring, restlessness, nocturia, refreshed on waking? Insomnia pattern: onset (anxiety), maintenance (hormonal, pain), early morning (depression).</div></div>
      <div class="step"><div class="sn" style="background:#064E3B">4</div><div class="st"><span class="sh">Bowel & Digestive History</span> Frequency, Bristol stool type (1–7), colour, urgency, bloating, flatulence, reflux, nausea. Bowel frequency: 1–3x/day normal. Type 1–2 = constipation; Type 6–7 = diarrhoea. Last colonoscopy? Blood PR?</div></div>
      <div class="step"><div class="sn" style="background:#064E3B">5</div><div class="st"><span class="sh">Stress & Emotional History</span> Current stressors (work, relationships, finances, health anxiety). Trauma history (ACEs — adverse childhood experiences). Coping mechanisms. Support system. Purpose and meaning. Spirituality/faith.</div></div>
      <div class="step"><div class="sn" style="background:#064E3B">6</div><div class="st"><span class="sh">Exercise & Movement</span> Type, frequency, duration, intensity. Sedentary time. Occupation (sitting vs standing). Recreational activity. Previous sporting history.</div></div>
      <div class="step"><div class="sn" style="background:#064E3B">7</div><div class="st"><span class="sh">Toxic Load Assessment</span> Smoking (pack-years), alcohol (units/week), recreational drugs, caffeine (cups/day), occupational chemical exposure, medications (OTC + prescribed + herbal), air quality at home/work.</div></div>
    </div>
    <div class="pearl"><div class="pl">🟡 Pearl — The First Question</div><div class="pt">"What do you think is causing your problem?" — Ask this first, always. Patients often know the cause (stress, diet, a specific event) but feel it won't be taken seriously. This question builds rapport, saves time, and reveals the patient's health belief model — which determines compliance with your recommendations.</div></div>`},
  {t:"Prakriti Assessment — Ayurvedic Constitution",badge:"BNYS Integration",c:`
    <div class="alert a-grn"><div class="a-label">Prakriti = Individual Constitutional Type</div>Determined at conception — unchangeable. Governs susceptibility to disease, drug response, optimal diet and lifestyle. Vikriti = current imbalanced state (what brings patient to clinic).</div>
    <table class="tbl"><thead><tr><th>Feature</th><th>Vata (Air+Space)</th><th>Pitta (Fire+Water)</th><th>Kapha (Earth+Water)</th></tr></thead><tbody>
      <tr><td>Body frame</td><td>Thin, bony, variable</td><td>Medium, muscular</td><td>Large, stocky, gains easily</td></tr>
      <tr><td>Skin</td><td>Dry, rough, cool</td><td>Oily, warm, reddish, prone to rash</td><td>Thick, oily, pale, cool</td></tr>
      <tr><td>Hair</td><td>Dry, brittle, frizzy</td><td>Fine, oily, early greying/baldness</td><td>Thick, oily, lustrous</td></tr>
      <tr><td>Digestion</td><td>Variable, bloating, gas</td><td>Strong, hyperacid, reflux</td><td>Slow, heavy, nausea</td></tr>
      <tr><td>Bowels</td><td>Constipation, dry, hard</td><td>Loose, frequent, diarrhoea-prone</td><td>Slow, regular, formed</td></tr>
      <tr><td>Sleep</td><td>Light, interrupted, insomnia</td><td>Moderate, vivid dreams, wakes hot</td><td>Deep, prolonged, hard to wake</td></tr>
      <tr><td>Mind/emotion</td><td>Anxious, creative, fearful, quick</td><td>Sharp, competitive, irritable, focused</td><td>Calm, loyal, possessive, slow to anger</td></tr>
      <tr><td>Climate preference</td><td>Hates cold/wind, loves warmth</td><td>Hates heat, loves cool</td><td>Hates cold/damp, loves dry heat</td></tr>
      <tr><td>Disease tendency</td><td>Joint pain, nervous disorders, constipation, insomnia</td><td>Inflammation, ulcers, liver disease, skin</td><td>Obesity, T2DM, respiratory, sinusitis</td></tr>
      <tr><td>Pulse quality</td><td>Thin, irregular, rapid (snake)</td><td>Moderate, strong, bounding (frog)</td><td>Slow, deep, steady (swan)</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Clinical Application</div><div class="pt">Most patients are dual constitution (Vata-Pitta, Pitta-Kapha). Pure single types are rare. Identify the PRIMARY dosha — this guides diet, hydrotherapy temperature choice, massage oil, and herb selection. Vata → warm oil massage, warm water therapy, grounding foods. Pitta → cool hydrotherapy, anti-inflammatory diet, bitter herbs. Kapha → vigorous dry massage, hot/cold contrast therapy, light stimulating diet, pungent herbs.</div></div>`},
  {t:"Tongue & Pulse Diagnosis — Clinical Basics",badge:"BNYS Specific",c:`
    <table class="tbl"><thead><tr><th>Parameter</th><th>Finding</th><th>Significance</th></tr></thead><tbody>
      <tr><td>Tongue — Colour</td><td>Pale pink (normal)</td><td>Healthy blood and Qi</td></tr>
      <tr><td></td><td>Pale/white</td><td>Blood deficiency, anaemia, cold</td></tr>
      <tr><td></td><td>Red/crimson</td><td>Heat excess, yin deficiency, fever</td></tr>
      <tr><td></td><td>Purple/dusky</td><td>Blood stagnation, circulatory issue</td></tr>
      <tr><td>Tongue — Coat</td><td>Thin white (normal)</td><td>Healthy stomach function</td></tr>
      <tr><td></td><td>Thick white</td><td>Cold, damp accumulation, SIBO</td></tr>
      <tr><td></td><td>Thick yellow</td><td>Heat, infection, liver/GB stress</td></tr>
      <tr><td></td><td>No coat (peeled)</td><td>Yin/fluid deficiency, chronic illness</td></tr>
      <tr><td>Tongue — Shape</td><td>Swollen/scalloped edges</td><td>Spleen Qi deficiency, dampness</td></tr>
      <tr><td></td><td>Thin/narrow</td><td>Blood/yin deficiency</td></tr>
      <tr><td></td><td>Cracks (midline)</td><td>Stomach yin deficiency, chronic stress</td></tr>
      <tr><td>Pulse — Rate</td><td>60–100 bpm (normal)</td><td>Healthy heart rate</td></tr>
      <tr><td>Pulse — Quality</td><td>Wiry/taut</td><td>Liver Qi stagnation, stress, pain</td></tr>
      <tr><td></td><td>Slippery/rolling</td><td>Dampness/phlegm, pregnancy</td></tr>
      <tr><td></td><td>Thin/thready</td><td>Blood/yin deficiency, anaemia</td></tr>
      <tr><td></td><td>Deep/sinking</td><td>Interior condition, kidney deficiency</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Integration Pearl</div><div class="pt">Tongue diagnosis is more reliable than pulse for beginners — the tongue doesn't change with practitioner pressure or patient anxiety. Always examine in natural light (not fluorescent). Ask patient not to eat, drink coffee/tea, or brush tongue for 1 hour before. Most significant finding: tongue body colour reflects chronic constitution; tongue coat reflects current digestive state.</div></div>`}
]};

const D_DIFFDIAG = {
dif:[
  {t:"Chest Pain — Differential Diagnosis",badge:"Emergency",c:`
    <div class="alert a-red"><div class="a-label">Rule Out Life-Threatening First ★</div>Always exclude ACS, PE, aortic dissection, tension pneumothorax before considering benign causes. These 4 kill within minutes to hours.</div>
    <table class="tbl"><thead><tr><th>Diagnosis</th><th>Character</th><th>Key Features</th><th>Naturopathic Role</th></tr></thead><tbody>
      <tr><td>ACS / MI ★</td><td>Crushing, radiates jaw/arm, &gt;20 min</td><td>Diaphoresis, nausea, ECG changes, troponin ↑</td><td>REFER EMERGENCY — no naturopathic Rx</td></tr>
      <tr><td>Pulmonary embolism ★</td><td>Pleuritic, sudden onset, worse breathing</td><td>Tachycardia, hypoxia, Wells score, D-dimer, CTPA</td><td>REFER EMERGENCY</td></tr>
      <tr><td>Aortic dissection ★</td><td>Tearing, worst ever, radiates to back</td><td>BP differential both arms, wide mediastinum CXR</td><td>REFER EMERGENCY</td></tr>
      <tr><td>GERD / oesophageal</td><td>Burning, substernal, worse lying/bending</td><td>Relieved antacids, waterbrash, post-meal</td><td>Diet, elevation, DGL, probiotics</td></tr>
      <tr><td>Musculoskeletal</td><td>Sharp, localised, worse movement/palpation</td><td>Reproducible on pressing, follows injury</td><td>Physical therapy, anti-inflammatory herbs</td></tr>
      <tr><td>Costochondritis</td><td>Sharp, anterior chest, worse breathing</td><td>Tender on sternal/costal palpation</td><td>NSAID herbs (willow, turmeric), rest</td></tr>
      <tr><td>Anxiety/panic</td><td>Tight, squeezing, with palpitations</td><td>Breathlessness, fear, tingling, resolves 20 min</td><td>Breathing techniques, adaptogens, CBT</td></tr>
      <tr><td>Pleurisy</td><td>Pleuritic, worse inspiration</td><td>Pleural rub, fever, follows respiratory illness</td><td>Rest, anti-inflammatory — identify cause</td></tr>
    </tbody></table>`},
  {t:"Abdominal Pain — Differential by Location",badge:"Essential",c:`
    <table class="tbl"><thead><tr><th>Location</th><th>Top Differentials</th><th>Key Features</th></tr></thead><tbody>
      <tr><td>RUQ</td><td>Cholecystitis, biliary colic, hepatitis, Fitz-Hugh-Curtis</td><td>Murphy's sign, fat-food trigger, jaundice</td></tr>
      <tr><td>LUQ</td><td>Splenic pathology, pancreatitis, gastric ulcer, renal</td><td>Kehr's sign (diaphragmatic irritation → left shoulder pain)</td></tr>
      <tr><td>RIF</td><td>Appendicitis, ovarian cyst/torsion, ectopic, IBD (Crohn's), psoas abscess</td><td>Rovsing's, psoas, obturator signs</td></tr>
      <tr><td>LIF</td><td>Diverticulitis, sigmoid volvulus, IBD (UC), ovarian</td><td>"Left-sided appendicitis" in elderly</td></tr>
      <tr><td>Epigastric</td><td>PUD, GERD, pancreatitis, ACS (BEWARE), gastritis</td><td>Always do ECG — MI can present as epigastric pain</td></tr>
      <tr><td>Periumbilical</td><td>Early appendicitis (migrates RIF), SBO, mesenteric ischaemia</td><td>Migration to RIF = appendicitis until proven otherwise</td></tr>
      <tr><td>Suprapubic</td><td>UTI, cystitis, PID, fibroids, prostatitis, appendicitis (pelvic)</td><td>MSSU, pelvic exam, pregnancy test (women)</td></tr>
      <tr><td>Generalised</td><td>Peritonitis, gastroenteritis, IBS, mesenteric adenitis, DKA</td><td>Peritonism: rigidity, guarding, rebound — REFER</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Red Flags — Refer Immediately</div><div class="pt">Rigid abdomen · Rebound tenderness · Haemodynamic instability · Signs of peritonism · Suspected ectopic pregnancy (women of reproductive age + abdominal pain + amenorrhoea = ectopic until proven otherwise) · Obstruction (vomiting + distension + no bowel sounds) · Any severe pain not improving in 2 hours.</div></div>`},
  {t:"Headache — Differential Diagnosis",badge:"Common",c:`
    <div class="alert a-red"><div class="a-label">Red Flag Headaches — SNOOP ★</div>Systemic symptoms (fever, weight loss) · Neurological signs · Onset sudden (thunderclap) · Older age (&gt;50 new headache) · Prior history change (pattern change in known migraineur) → CT/LP mandatory before naturopathic treatment.</div>
    <table class="tbl"><thead><tr><th>Type</th><th>Location</th><th>Character</th><th>Duration</th><th>Naturopathic Approach</th></tr></thead><tbody>
      <tr><td>Tension headache</td><td>Bilateral, band-like</td><td>Pressure/tightness, mild-moderate</td><td>30 min–7 days</td><td>Magnesium 400mg, peppermint oil topical, stress management, posture</td></tr>
      <tr><td>Migraine (without aura)</td><td>Unilateral</td><td>Pulsating, moderate-severe, nausea, photophobia</td><td>4–72 hrs</td><td>Magnesium 600mg, riboflavin 400mg, CoQ10, feverfew, avoid triggers</td></tr>
      <tr><td>Migraine with aura</td><td>Unilateral</td><td>Preceded by visual/sensory aura 20–60 min</td><td>4–72 hrs</td><td>Same + omega-3, identify food triggers (tyramine, alcohol, chocolate)</td></tr>
      <tr><td>Cluster headache</td><td>Unilateral orbital/periorbital</td><td>Excruciating, boring, autonomic features (watering eye)</td><td>15–180 min, clusters over weeks</td><td>Melatonin 10mg at night, refer for oxygen therapy — very limited naturopathic Rx</td></tr>
      <tr><td>Cervicogenic</td><td>Occipital, radiates frontal</td><td>Dull, worsened by neck movement</td><td>Hours–days</td><td>Physiotherapy, chiropractic, hydrotherapy, posture correction</td></tr>
      <tr><td>Subarachnoid ★</td><td>Global, "thunderclap"</td><td>"Worst headache of life" sudden onset</td><td>Constant → EMERGENCY</td><td>REFER EMERGENCY — do not treat</td></tr>
    </tbody></table>`},
  {t:"Fatigue — Differential Diagnosis",badge:"Most Common",c:`
    <table class="tbl"><thead><tr><th>Category</th><th>Cause</th><th>Key Features</th><th>Tests</th><th>Naturopathic Focus</th></tr></thead><tbody>
      <tr><td>Endocrine</td><td>Hypothyroidism</td><td>Cold intolerance, weight gain, constipation, bradycardia</td><td>TSH, free T4</td><td>Selenium, iodine, ashwagandha — support alongside medication</td></tr>
      <tr><td>Endocrine</td><td>Adrenal insufficiency</td><td>Fatigue worse mornings, salt craving, postural hypotension</td><td>Morning cortisol, ACTH stim</td><td>Adaptogens, B5, Vit C — refer for diagnosis first</td></tr>
      <tr><td>Haematological</td><td>Iron deficiency anaemia</td><td>Pallor, dyspnoea on exertion, pica, koilonychia</td><td>CBC, ferritin, serum iron</td><td>Iron-rich foods, Vit C with iron, remove inhibitors (tea/coffee with meals)</td></tr>
      <tr><td>Haematological</td><td>B12/folate deficiency</td><td>Fatigue, glossitis, neuropathy, macrocytosis</td><td>B12, folate, homocysteine</td><td>Methylcobalamin (B12), methylfolate — correct deficiency</td></tr>
      <tr><td>Mental health</td><td>Depression</td><td>Low mood, anhedonia, sleep change, cognitive slowing</td><td>PHQ-9, TSH (exclude thyroid)</td><td>Exercise, omega-3, St John's Wort (mild-moderate), CBT, sunlight</td></tr>
      <tr><td>Sleep disorder</td><td>OSA</td><td>Non-refreshing sleep, snoring, witnessed apnoeas, morning headache</td><td>Epworth, sleep study</td><td>Weight loss, lateral sleep position, CPAP — refer sleep clinic</td></tr>
      <tr><td>Infection</td><td>Post-viral (COVID, EBV)</td><td>Follows acute infection, PEM (exertion worsens)</td><td>EBV serology, inflammatory markers</td><td>Pacing, rest, Vit C, zinc, adaptogens — AVOID vigorous exercise (worsens PEM)</td></tr>
      <tr><td>Metabolic</td><td>T2DM / prediabetes</td><td>Polyuria, polydipsia, blurred vision, recurrent infections</td><td>FBG, HbA1c, OGTT</td><td>Low GI diet, berberine, exercise, weight loss</td></tr>
    </tbody></table>`}
,
  {t:"Skin Rash — Diagnostic Approach",badge:"Differential",c:`
    <div class="steps">
      <div class="step"><div class="sn" style="background:#be185d">1</div><div class="st"><span class="sh">Describe the lesion (SCAM)</span> S — Size/Shape. C — Colour. A — Arrangement (grouped/linear/dermatomal/scattered). M — Morphology: macule (flat) → papule (raised &lt;5mm) → plaque (raised &gt;5mm) → vesicle (fluid &lt;5mm) → bulla (&gt;5mm) → pustule (pus) → wheal (transient/urticaria).</div></div>
      <div class="step"><div class="sn" style="background:#be185d">2</div><div class="st"><span class="sh">Key diagnostic questions</span> Itch: present (eczema, urticaria, scabies, lichen planus) or absent (psoriasis, pityriasis). Distribution: sun-exposed (photosensitivity, SLE, rosacea), flexures (eczema), extensor (psoriasis), dermatomal (herpes zoster), palms and soles (secondary syphilis, scabies, HFMD). Systemic features: fever (viral exanthem, meningococcal, Kawasaki), arthralgia (SLE, reactive), weight loss (malignancy).</div></div>
    </div>
    <table class="tbl"><thead><tr><th>Pattern</th><th>Distribution</th><th>Key Feature</th><th>Diagnosis</th></tr></thead><tbody>
      <tr><td>Silver scaly plaques</td><td>Extensor surfaces, scalp, nails</td><td>Auspitz sign, nail pitting</td><td>Psoriasis</td></tr>
      <tr><td>Erythematous, weeping, pruritic</td><td>Flexures (cubital, popliteal)</td><td>Personal/family atopy</td><td>Atopic eczema</td></tr>
      <tr><td>Vesicles — dermatomal ★</td><td>Single dermatome, unilateral</td><td>Pain precedes rash 2–3 days</td><td>Herpes zoster (shingles)</td></tr>
      <tr><td>Butterfly malar rash</td><td>Cheeks, spares nasolabial fold</td><td>Photosensitive, systemic features</td><td>SLE</td></tr>
      <tr><td>Transient wheals</td><td>Anywhere, migrating, &lt;24hrs</td><td>Intense itch</td><td>Urticaria</td></tr>
      <tr><td>Target (iris) lesions</td><td>Extremities, trunk</td><td>Concentric rings</td><td>Erythema multiforme</td></tr>
      <tr><td>Petechiae/purpura ★</td><td>Non-blanching (glass test)</td><td>Fever = EMERGENCY</td><td>Vasculitis, meningococcal, ITP</td></tr>
      <tr><td>Annular scaly ring</td><td>Trunk, limbs</td><td>Clear centre, advancing edge</td><td>Tinea (ringworm)</td></tr>
      <tr><td>Burrows — interdigital</td><td>Web spaces, wrists, waist</td><td>Nocturnal itch, household contacts</td><td>Scabies</td></tr>
    </tbody></table>`},
  {t:"Weight Gain, Oedema & Back Pain — Differentials",badge:"Differential",c:`
    <div style="font-weight:700;color:var(--em-dk);margin-bottom:6px">UNEXPLAINED WEIGHT GAIN</div>
    <table class="tbl"><thead><tr><th>Cause</th><th>Key Features</th><th>Tests</th></tr></thead><tbody>
      <tr><td>Hypothyroidism ★</td><td>Cold intolerance, fatigue, constipation, dry skin, bradycardia</td><td>TSH ★, free T4</td></tr>
      <tr><td>PCOS</td><td>Irregular periods, hirsutism, acne, central obesity, acanthosis nigricans</td><td>LH, FSH, testosterone, USS pelvis, fasting insulin</td></tr>
      <tr><td>Cushing's syndrome</td><td>Central obesity, moon face, buffalo hump, purple striae, proximal myopathy, HTN</td><td>24hr urinary cortisol, overnight dexamethasone suppression test</td></tr>
      <tr><td>Insulin resistance</td><td>Central obesity, acanthosis nigricans, fatigue after carbs, FHx T2DM</td><td>HOMA-IR, fasting glucose, HbA1c</td></tr>
      <tr><td>Drug-induced ★</td><td>Antipsychotics (olanzapine), antidepressants (mirtazapine), steroids, insulin</td><td>Medication timeline vs weight gain onset</td></tr>
      <tr><td>Rapid fluid retention</td><td>&gt;2kg/week, ankle oedema, breathlessness</td><td>BNP, renal function, urinalysis — refer urgently</td></tr>
    </tbody></table>
    <div style="font-weight:700;color:var(--em-dk);margin:10px 0 6px">MONOARTHRITIS vs POLYARTHRITIS</div>
    <table class="tbl"><thead><tr><th>Diagnosis</th><th>Joints</th><th>Key Features</th><th>Test</th></tr></thead><tbody>
      <tr><td>Septic arthritis ★</td><td>Mono (knee 50%)</td><td>Hot, swollen, fever, cannot weight-bear</td><td>ASPIRATE FIRST + blood cultures</td></tr>
      <tr><td>Gout</td><td>1st MTP ★, ankle, knee</td><td>Excruciating overnight onset, tophi (chronic)</td><td>Aspirate: needle crystals, negatively birefringent</td></tr>
      <tr><td>Pseudogout</td><td>Knee ★, wrist (elderly)</td><td>X-ray: chondrocalcinosis ★</td><td>Aspirate: rhomboid crystals, positively birefringent</td></tr>
      <tr><td>Rheumatoid arthritis</td><td>MCPs, PIPs, wrists — symmetric</td><td>Morning stiffness &gt;1hr, spares DIPs</td><td>RF, anti-CCP (most specific)</td></tr>
      <tr><td>Psoriatic arthritis</td><td>DIP, dactylitis (sausage digit ★), asymmetric</td><td>Psoriasis (check scalp, nails, umbilicus)</td><td>No specific test — X-ray advanced</td></tr>
    </tbody></table>`}
]};

const D_DRUGSIDE = {
drg:[
  {t:"Common Drug Side Effects — BNYS Relevance",badge:"Essential",c:`
    <div class="alert a-grn"><div class="a-label">Why This Matters for BNYS</div>Many patients present to naturopathic clinics with symptoms that are actually drug side effects. Recognising these prevents misdiagnosis and inappropriate treatment. Always review the medication list before attributing symptoms to disease.</div>
    <table class="tbl"><thead><tr><th>Drug Class</th><th>Common Examples</th><th>Key Side Effects</th><th>Naturopathic Management</th></tr></thead><tbody>
      <tr><td>Statins</td><td>Atorvastatin, rosuvastatin</td><td>Myalgia/myopathy (5–10%), fatigue, CoQ10 depletion, liver enzyme ↑</td><td>CoQ10 100–200mg/day, monitor CK, magnesium for muscle cramps</td></tr>
      <tr><td>ACE inhibitors</td><td>Enalapril, ramipril, lisinopril</td><td>Dry cough (10–15%), hyperkalaemia, angioedema (rare but dangerous)</td><td>Explain cough is drug effect; angioedema = emergency</td></tr>
      <tr><td>Metformin</td><td>Glucophage</td><td>GI upset, nausea, diarrhoea (30%), B12 deficiency (long-term)</td><td>Take with food, B12 monitoring/supplementation, probiotics for GI</td></tr>
      <tr><td>PPIs</td><td>Omeprazole, pantoprazole</td><td>Mg deficiency, B12 deficiency, increased fracture risk, C.diff risk, SIBO</td><td>Magnesium, B12, DGL liquorice, consider deprescribing with diet</td></tr>
      <tr><td>SSRIs</td><td>Sertraline, fluoxetine, escitalopram</td><td>Nausea (initial), sexual dysfunction, weight gain, insomnia/somnolence, emotional blunting</td><td>Zinc, Mg, omega-3 as adjuncts; never stop abruptly — taper only</td></tr>
      <tr><td>NSAIDs</td><td>Ibuprofen, diclofenac, naproxen</td><td>GI ulceration, renal impairment, fluid retention, CVD risk (COX-2)</td><td>Always with food; natural alternatives: turmeric, willow bark, omega-3</td></tr>
      <tr><td>Corticosteroids</td><td>Prednisolone, dexamethasone</td><td>Weight gain, hyperglycaemia, osteoporosis, adrenal suppression, Cushing's features</td><td>Calcium+D3, vitamin K2, blood glucose monitoring; never stop abruptly</td></tr>
      <tr><td>Thyroid (levothyroxine)</td><td>Thyroxine</td><td>Palpitations, insomnia, tremor if over-replaced; hair loss initially</td><td>Take 30–60 min before food; calcium/iron supplements 4 hrs apart; monitor TSH</td></tr>
      <tr><td>Antihypertensives (beta-blockers)</td><td>Metoprolol, atenolol</td><td>Fatigue, cold extremities, exercise intolerance, depression, erectile dysfunction</td><td>CoQ10, magnesium; do not stop abruptly (rebound hypertension)</td></tr>
      <tr><td>Antibiotics</td><td>Amoxicillin, ciprofloxacin</td><td>GI upset, dysbiosis, C.diff (clindamycin/ciprofloxacin), photosensitivity (quinolones)</td><td>Probiotics (2 hrs away from dose), during and 4 weeks after course</td></tr>
    </tbody></table>`},
  {t:"Drug-Nutrient Depletions — Key Reference",badge:"Clinical",c:`
    <table class="tbl"><thead><tr><th>Drug</th><th>Nutrient Depleted</th><th>Symptoms of Depletion</th><th>Replacement Dose</th></tr></thead><tbody>
      <tr><td>Statins</td><td>CoQ10</td><td>Fatigue, muscle weakness, myalgia</td><td>CoQ10 100–200mg/day with fat</td></tr>
      <tr><td>Metformin</td><td>B12, folate</td><td>Neuropathy, macrocytic anaemia, cognitive decline</td><td>Methylcobalamin 1000mcg/day, methylfolate 400mcg</td></tr>
      <tr><td>PPIs</td><td>Mg, B12, Ca, Zn, Fe</td><td>Muscle cramps, fatigue, fractures, anaemia</td><td>Mg glycinate 300mg, B12 1000mcg, Ca+D3</td></tr>
      <tr><td>Oral contraceptives</td><td>B6, B12, folate, Zn, Mg, C</td><td>Depression, PMS, fatigue, poor wound healing</td><td>B-complex + Zn 15mg + Mg 300mg + Vit C 500mg</td></tr>
      <tr><td>ACE inhibitors/diuretics</td><td>Zinc, Mg, potassium</td><td>Taste changes, muscle cramps, weakness</td><td>Zn 15mg, Mg 300mg, potassium-rich foods</td></tr>
      <tr><td>Corticosteroids</td><td>Ca, Mg, K, B6, Zn, Vit C, D</td><td>Osteoporosis, immune suppression, wound healing</td><td>Ca 1000mg+D3 2000IU+K2 100mcg, Zn, Mg</td></tr>
      <tr><td>Antibiotics (prolonged)</td><td>Vitamins B, K, beneficial gut flora</td><td>Dysbiosis, fatigue, immune suppression</td><td>B-complex, probiotics, vit K2</td></tr>
      <tr><td>Beta-blockers</td><td>CoQ10, melatonin</td><td>Fatigue, exercise intolerance, sleep disturbance</td><td>CoQ10 100mg, melatonin 1–3mg at night</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Pearl — Deprescribing Opportunity</div><div class="pt">PPIs are the most overprescribed medication in primary care. 70% of PPI prescriptions have no clear indication after review. Naturopathic approach to PPI deprescribing: (1) Identify true indication (GERD vs functional). (2) Optimise diet (no late meals, no trigger foods, elevate HOB). (3) DGL liquorice 400mg before meals. (4) Reduce PPI by 50% every 2 weeks (rebound acid secretion = most common reason for failure). (5) H2 blocker bridge during taper. Success rate with naturopathic support: 65–70%.</div></div>`}
,
  {t:"Herb-Drug Interactions — Quick Reference",badge:"Safety ★",c:`
    <div class="alert a-red"><div class="a-label">Critical Interactions ★</div>St John's Wort interacts with 70+ drugs via CYP450 induction. Always take a full supplement history from every patient.</div>
    <table class="tbl"><thead><tr><th>Herb</th><th>Drug Class</th><th>Effect</th><th>Severity</th></tr></thead><tbody>
      <tr><td>St John's Wort</td><td>SSRIs, triptans</td><td>Serotonin syndrome</td><td>🔴 Severe</td></tr>
      <tr><td>St John's Wort</td><td>Warfarin, OCP, antiretrovirals, digoxin, cyclosporin</td><td>Drug levels ↓ → treatment failure</td><td>🔴 Severe — CYP3A4/P-gp induction</td></tr>
      <tr><td>Ginkgo biloba</td><td>Warfarin, aspirin, NSAIDs, clopidogrel</td><td>Bleeding risk ↑</td><td>🔴 Severe</td></tr>
      <tr><td>Licorice root</td><td>Antihypertensives, digoxin, diuretics</td><td>HTN ↑, hypokalaemia, digoxin toxicity</td><td>🟡 Moderate</td></tr>
      <tr><td>Valerian</td><td>Benzodiazepines, anaesthetics, alcohol</td><td>CNS depression ↑</td><td>🟡 Moderate</td></tr>
      <tr><td>Echinacea</td><td>Immunosuppressants (cyclosporin, tacrolimus)</td><td>Immunosuppression ↓</td><td>🟡 Moderate</td></tr>
      <tr><td>Ginseng</td><td>Warfarin, insulin, MAOIs</td><td>INR ↓, hypoglycaemia, serotonin syndrome</td><td>🟡 Moderate</td></tr>
      <tr><td>Kava kava</td><td>Hepatotoxic drugs, alcohol, CNS depressants</td><td>Hepatotoxicity ↑, CNS depression ↑</td><td>🔴 Severe</td></tr>
      <tr><td>Garlic (high dose)</td><td>Warfarin, aspirin</td><td>Bleeding risk ↑</td><td>🟡 Moderate</td></tr>
      <tr><td>Turmeric (high dose)</td><td>Warfarin, NSAIDs</td><td>Mild bleeding risk</td><td>🟢 Mild</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Stop Before Surgery</div><div class="pt">Stop ALL herbal supplements 2 weeks before elective surgery. Key ones: Garlic, Ginkgo, Ginseng, Ginger, St John's Wort, Valerian, Echinacea, Feverfew, Kava. They affect bleeding, anaesthesia depth, or wound healing. Inform the anaesthetist of all supplements at pre-assessment.</div></div>`}
],
syn:[
  {t:"Nutrient Synergy Matrix — Combinations That Amplify Each Other",badge:"Clinical Gold ★",c:`
    <div class="alert a-grn"><div class="a-label">Synergy Principle</div>Nutrients do not work in isolation — many have profound synergistic relationships where combining them produces effects far greater than either alone. Understanding synergy lets you design more effective protocols with lower doses and reduced cost. Conversely, certain combinations create antagonism and must be avoided.</div>
    <table class="tbl"><thead><tr><th>Nutrient A</th><th>Nutrient B</th><th>Synergy Effect</th><th>Mechanism</th><th>Clinical Use</th></tr></thead><tbody>
      <tr><td><strong>Vitamin D3</strong></td><td><strong>Vitamin K2 (MK-7)</strong></td><td>✅ Essential pair</td><td>D3 ↑ calcium absorption; K2 directs calcium into bone (osteocalcin) and away from arteries (MGP). D3 without K2 = calcium deposits in arteries.</td><td>All Ca+D3 protocols. Dose: D3 1000–5000 IU + K2 100–200mcg MK-7</td></tr>
      <tr><td><strong>Iron</strong></td><td><strong>Vitamin C</strong></td><td>✅ Absorption ↑ 3×</td><td>Vit C reduces Fe³⁺ → Fe²⁺ (absorbable form). Chelates iron in gut lumen maintaining solubility at higher pH.</td><td>Iron deficiency anaemia. Iron bisglycinate 25mg + Vit C 250mg together. Separate from tea/coffee/calcium by 2hrs.</td></tr>
      <tr><td><strong>Magnesium</strong></td><td><strong>Vitamin D3</strong></td><td>✅ Activation cofactor</td><td>Mg is required for every enzymatic step of Vit D activation (25-hydroxylation in liver; 1α-hydroxylation in kidney). Mg deficiency renders Vit D supplementation ineffective regardless of dose.</td><td>Always supplement Mg when giving therapeutic Vit D. Mg glycinate 300–400mg/day.</td></tr>
      <tr><td><strong>Curcumin</strong></td><td><strong>Piperine (BioPerine)</strong></td><td>✅ Bioavailability ↑ 2000%</td><td>Piperine inhibits CYP3A4 and P-glycoprotein in gut wall — dramatically slows curcumin metabolism. Raises absorption from ~1% to ~20%.</td><td>All curcumin protocols. Always use combined product or add 5–10mg piperine. Caution: piperine potentiates some drugs — check interactions.</td></tr>
      <tr><td><strong>Zinc</strong></td><td><strong>Vitamin A</strong></td><td>✅ Mutual activation</td><td>Zinc required for retinol-binding protein synthesis (transports Vit A). Without zinc, Vit A remains sequestered in liver stores.</td><td>Immune support, skin, wound healing. Zn 15–30mg + Vit A 5000IU. Critical in malnourished patients.</td></tr>
      <tr><td><strong>CoQ10</strong></td><td><strong>Omega-3 (EPA/DHA)</strong></td><td>✅ Cardiovascular synergy</td><td>CoQ10 restores mitochondrial ATP efficiency; omega-3 reduces membrane viscosity and inflammatory load. Additive cardioprotection via independent pathways.</td><td>CVD, heart failure, statin myopathy. CoQ10 ubiquinol 200mg + omega-3 3g/day.</td></tr>
      <tr><td><strong>Vitamin C</strong></td><td><strong>Vitamin E</strong></td><td>✅ Antioxidant recycling</td><td>Vit E quenches lipid ROS but becomes a radical itself. Vit C (ascorbate) regenerates Vit E from its radical form — extending antioxidant capacity without increasing dose.</td><td>Oxidative stress, cardiovascular prevention, photoprotection. Vit C 1g + Vit E 400IU mixed tocopherols.</td></tr>
      <tr><td><strong>NAC</strong></td><td><strong>Glycine</strong></td><td>✅ Glutathione synthesis</td><td>Glutathione = Glutamate + Cysteine + Glycine. NAC provides cysteine (rate-limiting). Glycine is often deficient in ageing. GlyNAC restores glutathione better than either alone.</td><td>Ageing, mitochondrial dysfunction, liver disease. GlyNAC: glycine 1.1g + NAC 0.8g per 10kg body weight.</td></tr>
      <tr><td><strong>Probiotics</strong></td><td><strong>Prebiotics (FOS/inulin)</strong></td><td>✅ Synbiotic effect</td><td>Prebiotics selectively feed supplemented probiotic strains — increasing colonisation, survival, and SCFA/butyrate production. Probiotics alone are transient; prebiotics extend their benefit.</td><td>Gut dysbiosis, IBS, immune support. Lactobacillus + inulin 5g/day. Separate from antibiotics by 2hrs.</td></tr>
      <tr><td><strong>Berberine</strong></td><td><strong>Alpha-lipoic acid</strong></td><td>✅ Insulin sensitisation ×2</td><td>Berberine activates AMPK via mitochondrial complex I inhibition; ALA activates AMPK via upstream SIRT1 and directly stimulates GLUT4 translocation. Additive glucose lowering from independent mechanisms.</td><td>T2DM, insulin resistance, PCOS, metabolic syndrome. Berberine 500mg TID + ALA 600mg/day.</td></tr>
      <tr><td><strong>5-HTP</strong></td><td><strong>Vitamin B6 (P5P)</strong></td><td>✅ Serotonin synthesis</td><td>5-HTP → serotonin requires aromatic amino acid decarboxylase — a B6-dependent enzyme. Without P5P, 5-HTP is decarboxylated peripherally causing nausea rather than centrally in the brain.</td><td>Depression, insomnia, anxiety. 5-HTP 100–300mg + P5P 25–50mg. Take P5P 30 min before 5-HTP.</td></tr>
      <tr><td><strong>Selenium</strong></td><td><strong>Iodine</strong></td><td>✅ Thyroid protection pair</td><td>Iodine is required for T4 synthesis. Selenium (as GPx and thioredoxin reductase) protects the thyroid from H₂O₂ generated during iodine organification. Iodine without selenium → thyroid oxidative damage → autoimmunity.</td><td>Thyroid support, Hashimoto's. Always give Se 100–200mcg when supplementing iodine. Selenium alone ↓ TPO antibodies 50% (Cochrane).</td></tr>
    </tbody></table>`},
  {t:"Nutrient Antagonism Matrix — Combinations to AVOID",badge:"Safety ★",c:`
    <div class="alert a-red"><div class="a-label">⚠️ Antagonistic Pairs — These Block Each Other or Cause Harm</div>Giving these together wastes money and can cause harm. Space them by 2–4 hours minimum, or choose non-competing forms.</div>
    <table class="tbl"><thead><tr><th>Nutrient A</th><th>Antagonist B</th><th>Problem</th><th>Solution</th></tr></thead><tbody>
      <tr><td><strong>Iron</strong></td><td><strong>Calcium</strong></td><td>🔴 Compete for DMT-1 transporter in duodenum → iron absorption ↓ 60%</td><td>Separate by ≥2 hours. Iron with Vit C in AM on empty stomach; calcium with meals or PM.</td></tr>
      <tr><td><strong>Iron</strong></td><td><strong>Zinc (high dose)</strong></td><td>🔴 Compete for same intestinal transporter. Zinc:iron ratio &gt;2:1 inhibits iron absorption.</td><td>Separate by ≥2hrs. At therapeutic iron doses, avoid simultaneous zinc &gt;15mg.</td></tr>
      <tr><td><strong>Zinc (high dose)</strong></td><td><strong>Copper</strong></td><td>🔴 Zinc induces metallothionein in gut cells → binds copper → blocks absorption. Chronic high zinc → copper deficiency anaemia and neuropathy.</td><td>For every 15mg zinc, add 1mg copper. Do not exceed 40mg/day without monitoring. Signs: anaemia unresponsive to iron, peripheral neuropathy.</td></tr>
      <tr><td><strong>Folate (high dose)</strong></td><td><strong>B12 deficiency (masked)</strong></td><td>🔴 High-dose folate corrects macrocytic anaemia while neurological B12 damage continues silently — degeneration becomes irreversible.</td><td>ALWAYS confirm and correct B12 before giving folate. Never give folate &gt;1mg without checking B12 status. Use methylcobalamin.</td></tr>
      <tr><td><strong>Calcium (high dose)</strong></td><td><strong>Levothyroxine</strong></td><td>🔴 Calcium chelates levothyroxine in GI tract → absorption ↓ 30–40% → hypothyroidism inadequately controlled.</td><td>Separate levothyroxine from calcium, iron, and magnesium by minimum 4 hours. Take thyroxine first thing on empty stomach.</td></tr>
      <tr><td><strong>5-HTP / Tryptophan</strong></td><td><strong>SSRIs / MAOIs</strong></td><td>🔴 Risk of serotonin syndrome — agitation, hyperthermia, clonus, autonomic instability. Potentially fatal.</td><td>Never combine 5-HTP with SSRIs/SNRIs without medical supervision. MAOI + 5-HTP = absolute contraindication.</td></tr>
      <tr><td><strong>Green tea / Quercetin / Coffee</strong></td><td><strong>Iron supplements</strong></td><td>🟡 Polyphenols chelate iron in gut lumen → absorption reduced 50–90%</td><td>Do not take iron with tea, coffee, or polyphenol supplements. Separate by 2 hours minimum.</td></tr>
      <tr><td><strong>Vit A (mega-dose)</strong></td><td><strong>Vitamin D receptor</strong></td><td>🟡 At pharmacological doses (&gt;25,000IU), Vit A antagonises Vit D receptor activity — reduces D3 efficacy.</td><td>Keep Vit A within physiological range (5000–10,000 IU). Do not use mega-dose Vit A when optimising Vit D therapy.</td></tr>
    </tbody></table>`},
  {t:"Drug-Nutrient Synergy — Using Drugs Better With Nutrition",badge:"Integrative",c:`
    <div class="alert a-blu"><div class="a-label">Integrative Principle</div>Many conventional drugs work better, are better tolerated, and can sometimes be dose-reduced when combined with targeted nutritional support. This is evidence-based integrative medicine — not replacing drugs, but enhancing their effectiveness and reducing side effects.</div>
    <table class="tbl"><thead><tr><th>Drug</th><th>Nutritional Synergist</th><th>Effect</th><th>Evidence</th></tr></thead><tbody>
      <tr><td><strong>Statins</strong></td><td>CoQ10 ubiquinol 200mg/day</td><td>Restores CoQ10 depleted by statin (shared mevalonate pathway). Reduces statin myalgia 54%. Improves exercise tolerance and energy.</td><td>★★★ Multiple RCTs</td></tr>
      <tr><td><strong>Metformin</strong></td><td>Berberine 500mg TID + ALA 600mg + Mg 400mg</td><td>Additive glucose lowering via complementary AMPK pathways. Berberine allows lower metformin doses. Addresses B12/folate depletion.</td><td>★★★ RCT: comparable HbA1c reduction to metformin 1500mg</td></tr>
      <tr><td><strong>SSRIs</strong></td><td>EPA-predominant omega-3 2–4g/day + methylfolate 15mg</td><td>Omega-3 augments antidepressant response — 50% better response than SSRI alone. Methylfolate (MTHFR support) further augments response in poor methylators.</td><td>★★★ Meta-analysis (n=1,233)</td></tr>
      <tr><td><strong>PPIs (during taper)</strong></td><td>DGL liquorice 400mg + zinc carnosine 75mg + melatonin 6mg</td><td>DGL stimulates mucus; zinc carnosine repairs mucosal barrier; melatonin reduces gastric acid and heals LES. Bridge during PPI deprescribing (50% dose reduction every 2 weeks).</td><td>★★ Individual RCTs</td></tr>
      <tr><td><strong>ACE inhibitors / ARBs</strong></td><td>CoQ10 200mg + Mg glycinate 400mg + beet juice 250ml</td><td>Additive 5–17mmHg systolic reduction via independent vasodilation pathways. Addresses Mg depletion from co-prescribed diuretics. May allow dose reduction over 6 months.</td><td>★★★ CoQ10 + Mg meta-analyses</td></tr>
      <tr><td><strong>Chemotherapy (supportive)</strong></td><td>Glutamine 10–30g/day + Vit D + omega-3</td><td>Glutamine reduces CIPN severity and mucositis; protects gut barrier during fluorouracil. Omega-3 preserves muscle mass (cancer cachexia). Only with oncologist approval.</td><td>★★★ Multiple RCTs for glutamine in mucositis/CIPN</td></tr>
      <tr><td><strong>Warfarin</strong></td><td>Vit K2 MK-7 45–90mcg consistent daily</td><td>Stable low-dose K2 improves INR stability — inconsistent dietary Vit K is the main cause of INR fluctuation. Counter-intuitive but evidence-based.</td><td>★★ RCT: reduces INR variability 30%. Only under anticoagulation clinic supervision.</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Communication Rule — Never Reduce Drugs Unilaterally</div><div class="pt">Any nutritional synergy that may allow drug dose reduction MUST be coordinated with the prescribing physician. Your role: document the evidence, discuss with the patient, communicate with the prescriber in writing. A brief clinical note with the evidence basis builds referral relationships and protects both patient and practitioner legally. Never advise dose reduction without prescriber knowledge.</div></div>`},
  {t:"Comprehensive Depletion Reference — All Major Drug Classes",badge:"Reference ★",c:`
    <table class="tbl"><thead><tr><th>Drug / Class</th><th>Depleted Nutrients</th><th>Key Manifestations</th><th>Replacement Protocol</th><th>Priority</th></tr></thead><tbody>
      <tr><td><strong>Statins</strong></td><td>CoQ10 ★★★, Vit D, selenium</td><td>Myalgia, fatigue, exercise intolerance, cognitive fog</td><td>CoQ10 ubiquinol 200mg, Vit D 2000IU, Se 100mcg</td><td>🔴 Start with statin</td></tr>
      <tr><td><strong>Metformin</strong></td><td>B12 ★★★, folate, thiamine</td><td>Peripheral neuropathy, macrocytic anaemia, ↑ homocysteine</td><td>Methylcobalamin 1000mcg/day, methylfolate 400mcg, B1 100mg. Check B12 annually.</td><td>🔴 Monitor annually</td></tr>
      <tr><td><strong>PPIs</strong></td><td>Mg ★★★, B12 ★★★, Ca, Zn, Fe, Vit C</td><td>Hypomagnesaemia (cramps, arrhythmia), B12 deficiency, fractures</td><td>Mg glycinate 300mg, sublingual B12 1000mcg, Ca+D3, Zn 15mg</td><td>🔴 Especially if &gt;3 months</td></tr>
      <tr><td><strong>Oral Contraceptives</strong></td><td>B6 ★★★, B12, folate, Zn ★★, Mg, Vit C, selenium</td><td>Depression, PMS, poor libido, fatigue, ↑ homocysteine</td><td>B-complex with P5P 25mg + methylfolate 400mcg + methylcobalamin + Zn 15mg + Mg 300mg</td><td>🔴 Mental health critical</td></tr>
      <tr><td><strong>Corticosteroids</strong></td><td>Ca ★★★, Vit D ★★★, Mg, K, B6, Zn, Vit C, DHEA</td><td>Osteoporosis, muscle wasting, hyperglycaemia, immune suppression</td><td>Ca 1000mg + D3 3000IU + K2 100mcg (mandatory &gt;3 months). Mg 400mg, Vit C 1g, Zn 15mg.</td><td>🔴 Bone protection critical</td></tr>
      <tr><td><strong>Thiazide diuretics</strong></td><td>Mg ★★★, K ★★★, Zn, B1, CoQ10</td><td>Muscle cramps, weakness, arrhythmia, fatigue, worsened diabetes</td><td>Mg glycinate 400mg, K-rich diet (monitor serum K), Zn 15mg, B1 100mg</td><td>🔴 Arrhythmia risk</td></tr>
      <tr><td><strong>Loop diuretics</strong></td><td>Mg ★★★, K ★★★, Ca, Zn, B1, B6, Vit C</td><td>As thiazides but more severe. High risk of hypomagnesaemia-induced arrhythmia.</td><td>Mg glycinate 400–600mg, K (physician-prescribed), Ca+D3, B-complex, Vit C 500mg</td><td>🔴 Cardiac monitoring</td></tr>
      <tr><td><strong>Beta-blockers</strong></td><td>CoQ10 ★★, melatonin, Vit D</td><td>Fatigue, exercise intolerance, insomnia</td><td>CoQ10 ubiquinol 150mg, melatonin 0.5–1mg at bedtime, Vit D 2000IU</td><td>🟡 Moderate</td></tr>
      <tr><td><strong>SSRIs/SNRIs</strong></td><td>Zn ★★, Mg, folate, Vit D, melatonin</td><td>Worsened depression, sleep disruption, sexual dysfunction. Elderly: hyponatraemia (SIADH).</td><td>Zn 15mg, Mg glycinate 300mg, methylfolate 400–800mcg, Vit D 2000IU. Monitor Na in elderly.</td><td>🟡 Moderate</td></tr>
      <tr><td><strong>Anticonvulsants</strong></td><td>Folate ★★★, B12, Vit D ★★, Ca, biotin, Vit K, L-carnitine (valproate)</td><td>Megaloblastic anaemia, osteoporosis, NTD risk, carnitine deficiency</td><td>Methylfolate 5mg/day (women of childbearing age), Vit D 3000IU + Ca 1000mg, biotin 5mg, L-carnitine 1g if on valproate</td><td>🔴 Folate critical in women</td></tr>
      <tr><td><strong>Antibiotics (prolonged)</strong></td><td>Vit K ★★★, B vitamins, gut flora</td><td>Bleeding tendency (K), dysbiosis, immune suppression, C.diff risk</td><td>Probiotics (LGG + Saccharomyces boulardii) 2hrs from dose + 4 weeks post-course. Vit K2 45mcg if prolonged.</td><td>🟡 Moderate</td></tr>
    </tbody></table>`}
],
combo:[
  {t:"Dangerous Drug Combinations — Must Know",badge:"Safety Critical ★",c:`
    <div class="alert a-red"><div class="a-label">⚠️ These Combinations Can Kill — Screen Before Adding Any Natural Therapy</div>BNYS practitioners must recognise dangerous drug combinations patients may already be on before adding any natural intervention.</div>
    <table class="tbl"><thead><tr><th>Combination</th><th>Risk</th><th>Mechanism</th><th>Action</th></tr></thead><tbody>
      <tr><td><strong>MAOI + any serotonergic drug</strong> (SSRIs, TCAs, tramadol, pethidine, triptans, St John's Wort, 5-HTP)</td><td>🔴 FATAL — Serotonin Syndrome</td><td>MAO inhibition + serotonin agonism → massive serotonin accumulation → hyperthermia, clonus, seizures, cardiac arrhythmia, death</td><td>14-day washout after MAOI before any serotonergic drug. Absolute contraindication.</td></tr>
      <tr><td><strong>Warfarin + St John's Wort / Ginkgo / high-dose fish oil / Vit E</strong></td><td>🔴 Severe — Haemorrhage or Thrombosis</td><td>SJW (CYP3A4 induction) → ↓ warfarin → thrombosis. Antiplatelet herbs → ↑ bleeding risk. Unpredictable INR.</td><td>Check INR within 1 week of ANY herbal addition. Avoid SJW completely. Stop Ginkgo/Garlic 2 weeks before procedures.</td></tr>
      <tr><td><strong>ACE inhibitors + K-sparing diuretics + K supplements</strong></td><td>🔴 Severe — Hyperkalaemia → Cardiac arrest</td><td>Triple K-retention pathway → serum K &gt;6.5 → VF/VT. Classic in heart failure patients on ACEi + spironolactone.</td><td>Never give K supplements without checking serum K in patients on ACEi + spironolactone.</td></tr>
      <tr><td><strong>Methotrexate + NSAIDs</strong></td><td>🔴 Severe — MTX toxicity</td><td>NSAIDs displace MTX from plasma proteins + reduce renal clearance → MTX accumulation → bone marrow suppression, death</td><td>Never give NSAIDs (including ibuprofen) to patients on methotrexate without haematology review.</td></tr>
      <tr><td><strong>Digoxin + hypokalaemia-inducing drugs</strong> (thiazides, loop diuretics, laxatives)</td><td>🔴 Severe — Digoxin toxicity</td><td>Low K → digoxin receptor hypersensitivity → toxicity at therapeutic levels → bradycardia, heart block, VT</td><td>Monitor K obsessively in digoxin patients. Target K &gt;4.0 mmol/L. Mg supplementation supports K retention.</td></tr>
      <tr><td><strong>Lithium + NSAIDs / ACE inhibitors / thiazides</strong></td><td>🔴 Severe — Lithium toxicity</td><td>NSAIDs reduce prostaglandin-mediated renal blood flow → ↓ lithium clearance. ACEi/thiazides → compensatory Li reabsorption → toxicity.</td><td>Use paracetamol only for pain in lithium patients. Never add ACEi/thiazide without lithium level monitoring.</td></tr>
      <tr><td><strong>Sildenafil + Nitrates (GTN, isosorbide)</strong></td><td>🔴 FATAL — Severe hypotension</td><td>Both converge on cGMP → profound vasodilation → cardiac arrest. Irreversible once taken together.</td><td>ABSOLUTE contraindication. Ask every ED patient about nitrate use before recommending any ED herbs or supplements.</td></tr>
    </tbody></table>`},
  {t:"CYP450 Interactions — Practical Clinical Guide",badge:"Pharmacology",c:`
    <div class="alert a-info"><div class="a-label">CYP450 System — Why It Matters</div>The cytochrome P450 enzyme system metabolises 70–80% of all drugs. Herbs, foods, and supplements that inhibit (raise drug levels) or induce (lower drug levels) CYP enzymes create clinically significant interactions.</div>
    <table class="tbl"><thead><tr><th>Enzyme</th><th>Key Drugs Metabolised</th><th>Inhibitors (↑ drug levels)</th><th>Inducers (↓ drug levels)</th></tr></thead><tbody>
      <tr><td><strong>CYP3A4</strong> (50% of drugs)</td><td>Statins (simvastatin, atorvastatin), cyclosporin, tacrolimus, HIV meds, Ca channel blockers, midazolam, sildenafil</td><td>Grapefruit juice ★★★ (72hr irreversible), ketoconazole, clarithromycin, ritonavir, pomegranate juice, piperine (mild)</td><td>St John's Wort ★★★, rifampicin, carbamazepine, phenytoin → drug levels ↓ → treatment failure</td></tr>
      <tr><td><strong>CYP2D6</strong></td><td>Codeine (activation), beta-blockers, SSRIs, TCAs, tamoxifen (activation), tramadol</td><td>Fluoxetine, paroxetine (self-inhibiting), bupropion, curcumin (mild)</td><td>Genetic polymorphism — poor metabolisers cannot activate codeine (no analgesia) or tamoxifen (cancer treatment failure)</td></tr>
      <tr><td><strong>CYP2C9</strong></td><td>Warfarin (S-isomer), NSAIDs, phenytoin, glipizide, losartan activation</td><td>Fluconazole ★★★ (warfarin INR doubles — life-threatening), amiodarone, miconazole (topical also!), cranberry juice (mild)</td><td>Rifampicin, carbamazepine, St John's Wort → warfarin ↓ → thrombosis</td></tr>
      <tr><td><strong>CYP1A2</strong></td><td>Caffeine, theophylline, clozapine, haloperidol, olanzapine</td><td>Fluvoxamine ★★★ (raises clozapine/olanzapine → sedation, seizure), ciprofloxacin, cimetidine</td><td>Smoking ★★★ — smokers need higher antipsychotic doses; on quitting, levels rise → toxicity</td></tr>
    </tbody></table>
    <div class="pearl"><div class="pl">🟡 Grapefruit Warning — Practical List</div><div class="pt">Grapefruit furanocoumarins irreversibly inhibit intestinal CYP3A4 for 72 hours. One glass can raise simvastatin levels 3–16× → rhabdomyolysis. Avoid with: simvastatin ★★★, lovastatin, cyclosporin, tacrolimus, felodipine, midazolam, buspirone, sildenafil. Atorvastatin: low risk (hepatic metabolism). Rosuvastatin: safe (not CYP3A4 substrate). Always ask statin and immunosuppressant patients about grapefruit consumption.</div></div>`},
  {t:"Pharmaceutical-Naturopathic Combination Protocols",badge:"Integrative ★",c:`
    <div class="alert a-grn"><div class="a-label">Evidence-Based Drug + Natural Combinations</div>Validated combinations where evidence supports using both — producing better outcomes than either alone, with fewer side effects. Always coordinate with prescribing physician.</div>
    <table class="tbl"><thead><tr><th>Condition</th><th>Drug</th><th>Naturopathic Addition</th><th>Benefit</th><th>Evidence</th></tr></thead><tbody>
      <tr><td>T2DM</td><td>Metformin 1000mg BD</td><td>Berberine 500mg TID + ALA 600mg + chromium 200mcg + Mg 400mg</td><td>Additive HbA1c reduction; addresses B12/folate depletion; improves insulin sensitivity via additional pathways</td><td>★★★</td></tr>
      <tr><td>Hypertension</td><td>ACE inhibitor / ARB</td><td>CoQ10 200mg + Mg glycinate 400mg + beet juice 250ml/day</td><td>Additive 5–17mmHg systolic reduction. May allow dose reduction over 6 months.</td><td>★★★</td></tr>
      <tr><td>Depression</td><td>SSRI (sertraline, escitalopram)</td><td>EPA omega-3 2g/day + methylfolate 15mg + Zn 15mg + Vit D 3000IU</td><td>50% better response than SSRI alone. Addresses all nutrient depletions.</td><td>★★★</td></tr>
      <tr><td>Osteoporosis</td><td>Bisphosphonate (alendronate)</td><td>Ca 1000mg + D3 4000IU + K2 MK-7 180mcg + Mg 400mg</td><td>Drug prevents resorption; naturopathic protocol drives formation. Combined superior for BMD.</td><td>★★★</td></tr>
      <tr><td>Hypothyroidism</td><td>Levothyroxine</td><td>Selenium 200mcg + Zn 15mg + Mg 300mg (timed apart from thyroxine)</td><td>Se ↓ TPO antibodies 50%, improves T4→T3. Zn activates T3 receptors. Separate from thyroxine by 4hrs.</td><td>★★★ Se Cochrane; ★★ Zn</td></tr>
      <tr><td>IBD — UC maintenance</td><td>Mesalamine (5-ASA)</td><td>Curcumin 3g/day + probiotics (VSL#3) + omega-3 3g</td><td>Curcumin RCT equivalent to mesalamine for maintenance; combined reduces relapse to &lt;5%/year.</td><td>★★★</td></tr>
    </tbody></table>`}
]
};

